import React from 'react';
import { BrowserRouter as Router, Route, Routes, Navigate } from 'react-router-dom'; // Import Routes instead of Switch

import MasterLayout from './layouts/admin/MasterLayout';
import Home from './components/frontend/Home';
import Login from './layouts/frontend/auth/login';
import Register from './layouts/frontend/auth/register';

function App()
{
  return (
    <div className="App">
      <Router>
        {/* Use Routes instead of Switch */}
        <Routes>

          {/* Add this route to handle the root path */}
          <Route path="/" element={<Navigate replace to="/admin/dashboard" />} />
          <Route path="/home" element={<Home />} />
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          <Route path="/admin/*" element={<MasterLayout />} />

        </Routes>
      </Router>
    </div>
  );
}

export default App;
